mapper.select:
 SELECT COUNT(*)  
FROM  
    wfm_task_complete  



            task_name like concat(concat('%',#{taskName}),'%')




            process_name like concat(concat('%',#{processName}),'%')




            table_no like concat(concat('%',#{formNo}),'%')




            initiator_name like concat(concat('%',#{initiator}),'%')


    AND user_id = #{userId}
    AND start_time >= #{startFrom}
    AND start_time <= #{startTo}
    AND create_time >= #{completeFrom}
    AND create_time <= #{completeTo}
